import { moduleMetadata } from '@storybook/angular';
import { PfPaginationComponent } from './pagination.component';
const meta = {
    title: 'Composants graphiques/Pagination',
    component: PfPaginationComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Pagination accessible avec ellipses calculées automatiquement. Émet `(pageChange)`.",
            },
        },
    },
    decorators: [moduleMetadata({ imports: [PfPaginationComponent] })],
    render: (args) => ({
        props: args,
        template: `<pf-pagination
      [page]="page"
      [totalPages]="totalPages"
      [siblings]="siblings || 1"
      (pageChange)="page = $event"
    ></pf-pagination>`,
    }),
};
export default meta;
export const Default = {
    args: { page: 1, totalPages: 10 },
};
export const Middle = {
    args: { page: 5, totalPages: 20 },
};
export const FewPages = {
    args: { page: 2, totalPages: 4 },
};
export const ManyPages = {
    args: { page: 50, totalPages: 100, siblings: 2 },
};
export const FirstPage = {
    args: { page: 1, totalPages: 20 },
};
export const LastPage = {
    args: { page: 20, totalPages: 20 },
};
